                      onClick={() => select(sc.id)}
                    >
                      <div className="font-medium">{sc.name}</div>
                      <div className="text-muted">
                        id <code className="text-[10px]">{sc.id}</code> · cut line ≈{' '}
                        {run.toLocaleString()} mm
                        {crop != null ? ` · crop depth ${crop.toLocaleString()} mm` : ''}
                      </div>
                    </Btn>
                  </li>
                );
              })}
            </ul>
          </div>
        </>
      )}
    </Panel>
  );
}

